/* ===== Article Meta Top (category tag + reading time) ===== */
.article-meta-top {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}
.article-meta-top .card-tag {
  display: inline-block;
  padding: 4px 14px;
  border-radius: 12px;
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.article-meta-top span {
  color: var(--text-muted);
  font-size: 0.9rem;
}

/* ===== Related Section ===== */
.related-section {
  margin-top: 50px;
  padding-top: 30px;
  border-top: 2px solid var(--border);
}

/* ===== Cookie Banner ===== */
.cookie-banner {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
    background: var(--bg-secondary);
  border-top: 2px solid var(--accent);
  padding: 16px 24px;
  z-index: 9999;
  box-shadow: 0 -4px 30px rgba(0,0,0,.5);
  transform: translateY(100%);
  transition: transform .4s ease;
}
.cookie-banner.show { transform: translateY(0); }
.cookie-banner .cookie-inner {
  max-width: var(--max-width);
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
  flex-wrap: wrap;
}
.cookie-banner p {
  color: var(--text-secondary);
  font-size: 0.9rem;
  margin: 0;
  flex: 1;
  min-width: 240px;
}
.cookie-banner p a { color: var(--accent); text-decoration: underline; }
.cookie-btn {
  background: var(--accent);
  color: #fff;
  border: none;
  padding: 10px 28px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.95rem;
  font-weight: 600;
  white-space: nowrap;
  transition: background .2s;
}
.cookie-btn:hover { background: var(--accent-hover); }

/* ===== Performance: Reduce motion for users who prefer it ===== */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* ===== Print styles ===== */
@media print {
  .navbar, .footer, .cookie-banner, .affiliate-box, .adsense-placeholder { display: none !important; }
  body { background: #fff; color: #000; }
  .article-page { padding: 0; }
  a { color: #000; text-decoration: underline; }
